import React, { useState, useEffect } from 'react';
import './WaitingScreen.css';

const INITIAL_SECONDS = 8 * 60;

const DRIVER_INFO = {
  vehicle: '경북 12가 3456',
  driver: '김영주 기사님',
  eta: '10:38',
};

export default function WaitingScreen({ bookingInfo, onBack }) {
  const [seconds, setSeconds] = useState(INITIAL_SECONDS);
  const [arrived, setArrived] = useState(false);

  useEffect(() => {
    if (seconds <= 0) {
      setArrived(true);
      return;
    }
    const id = setInterval(() => setSeconds((s) => s - 1), 1000);
    return () => clearInterval(id);
  }, [seconds]);

  const mins = Math.ceil(seconds / 60);

  return (
    <div className="waiting-screen">
      {/* 헤더 */}
      <div className="waiting-header">
        <button className="back-btn-w" onClick={onBack}>‹</button>
        <h2 className="waiting-title">탑승 대기중</h2>
        <div style={{ width: 40 }} />
      </div>

      {/* 도착 예정 카드 */}
      <div className={`arrival-card ${arrived ? 'arrived' : ''}`}>
        <p className="arrival-time">
          {arrived ? '도착!' : `${mins}분 후 도착`}
        </p>
        <p className="arrival-sub">
          {arrived
            ? '차량이 도착했습니다. 탑승해 주세요!'
            : `차량이 ${bookingInfo.departure}으로 이동 중입니다`}
        </p>
        <div className="arrival-anim">
          <span className="arrival-bus">🚌</span>
          <span className="arrival-dots">• • •</span>
        </div>
      </div>

      {/* 간이 지도 카드 */}
      <div className="map-card">
        <div className="map-pin map-pin-departure">
          <span className="map-pin-icon">📍</span>
          <span className="map-pin-label">{bookingInfo.departure} 1번 출구</span>
        </div>

        <div className="map-route-area">
          <div className="map-dashed-line" />
          <div className="map-bus-moving">🚌</div>
        </div>

        <div className="map-pin map-pin-dest">
          <span className="map-pin-icon">🏛</span>
          <span className="map-pin-label">{bookingInfo.destination.name}</span>
        </div>
      </div>

      {/* 차량 정보 */}
      <div className="vehicle-info-card">
        <div className="vi-row">
          <span className="vi-label">차량번호</span>
          <span className="vi-value">{DRIVER_INFO.vehicle}</span>
        </div>
        <div className="vi-row">
          <span className="vi-label">기사님</span>
          <span className="vi-value">{DRIVER_INFO.driver}</span>
        </div>
        <div className="vi-row">
          <span className="vi-label">예상 도착</span>
          <span className="vi-value vi-eta">{DRIVER_INFO.eta}</span>
        </div>
      </div>

      {/* 취소 버튼 */}
      <div className="cancel-wrap">
        <button className="cancel-btn" onClick={onBack}>예약 취소</button>
      </div>
    </div>
  );
}
